(12, 'How do you modify existing records in a table?', 'INSERT', 'UPDATE', 'MODIFY', 'ALTER', 'B'),
(12, 'Which SQL command is used to delete a table structure from database?', 'DELETE', 'DROP', 'TRUNCATE', 'REMOVE', 'B'),
