(12, 'How do you find the highest value in a column?', 'MAX()', 'MIN()', 'SUM()', 'HIGH()', 'A'),
(12, 'Which SQL constraint ensures that a column cannot have NULL values?', 'UNIQUE', 'NOT NULL', 'CHECK', 'DEFAULT', 'B'),
(12, 'What does the UNIQUE constraint do?', 'Allows multiple null values only', 'Ensures all values in a column are different', 'Creates primary key', 'None of these', 'B'),
(12, 'What is a subquery in SQL?', 'A query executed in a separate session', 'A query nested inside another SQL query statement', 'A database view', 'None of these', 'B'),
