(12, 'Which SQL command is used to add a new column to an existing table?', 'UPDATE TABLE', 'ALTER TABLE', 'MODIFY TABLE', 'INSERT COLUMN', 'B'),
(12, 'What is a self-join?', 'Joining a table to a copy of itself', 'Joining a table to another database', 'Creating a table index', 'None of these', 'A'),
(12, 'Which SQL operator allows specifying multiple values in a WHERE clause?', 'BETWEEN', 'IN', 'LIKE', 'AND', 'B'),
