(12, 'Which join returns all records from right table and matching from left table?', 'LEFT JOIN', 'RIGHT JOIN', 'INNER JOIN', 'CROSS JOIN', 'B'),
(12, 'What does a CROSS JOIN produce?', 'Inner match only', 'Cartesian product of rows from both tables', 'Merged records with distinct keys', 'None of these', 'B'),
(12, 'Which function calculates the average value of a numeric column?', 'AVG()', 'AVERAGE()', 'MEAN()', 'COUNT()', 'A'),
