(12, 'Which keyword is used to assign an alias name to a column or table?', 'AS', 'LIKE', 'INTO', 'NAME', 'A'),
(12, 'What does the DEFAULT constraint do?', 'Forbids null values', 'Provides a default value for a column when no value is specified', 'Makes column primary key', 'None of these', 'B'),
(12, 'What is the default sort order for ORDER BY clause?', 'Descending (DESC)', 'Ascending (ASC)', 'Random order', 'Index order', 'B'),
(12, 'What is a composite primary key in databases?', 'A key that contains text and numbers', 'A primary key consisting of two or more columns to uniquely identify a row', 'A foreign key constraint', 'None of these', 'B'),
(12, 'How do you delete all rows in a table without deleting the table structure?', 'DROP TABLE', 'TRUNCATE TABLE', 'REMOVE TABLE', 'DELETE TABLE', 'B'),
