INSERT OR IGNORE INTO coding_challenges (id, title, description, difficulty, topic, sample_input, sample_output, test_cases_json) VALUES
(1, 'Two Sum', 'Given an array of integers nums and an integer target, return indices of the two numbers that add up to target. Each input has exactly one solution, and you may not use the same element twice. Use a HashMap for O(n) solution.', 'EASY', 'Arrays',
 'nums = [2,7,11,15], target = 9', '[0,1]',
 '[{"input":"nums=[2,7,11,15],target=9","expected":"[0,1]"},{"input":"nums=[3,2,4],target=6","expected":"[1,2]"}]'),
(2, 'Reverse String', 'Write a function that reverses a string in-place. The input string is given as an array of characters. Do it with O(1) extra memory using two pointers.', 'EASY', 'Strings',
 's = ["h","e","l","l","o"]', '["o","l","l","e","h"]',
 '[{"input":"[h,e,l,l,o]","expected":"[o,l,l,e,h]"},{"input":"[H,a,n,n,a,h]","expected":"[h,a,n,n,a,H]"}]'),
(3, 'Valid Parentheses', 'Given a string containing only "(", ")", "{", "}", "[" and "]", determine if the input string is valid. Open brackets must be closed by the same type and in correct order.', 'EASY', 'Stack',
 's = "()[]{}"', 'true',
 '[{"input":"()[]{}","expected":"true"},{"input":"(]","expected":"false"},{"input":"{[]}","expected":"true"}]'),
(4, 'Maximum Subarray', 'Given an integer array nums, find the contiguous subarray with the largest sum and return its sum. Use Kadane algorithm for O(n) solution.', 'MEDIUM', 'Dynamic Programming',
 'nums = [-2,1,-3,4,-1,2,1,-5,4]', '6',
 '[{"input":"[-2,1,-3,4,-1,2,1,-5,4]","expected":"6"},{"input":"[1]","expected":"1"},{"input":"[5,4,-1,7,8]","expected":"23"}]'),
(5, 'Binary Search', 'Given a sorted array of integers and a target value, return the index if found, else return -1. You must write an algorithm with O(log n) runtime complexity.', 'EASY', 'Binary Search',
 'nums = [-1,0,3,5,9,12], target = 9', '4',
 '[{"input":"[-1,0,3,5,9,12],target=9","expected":"4"},{"input":"[-1,0,3,5,9,12],target=2","expected":"-1"}]'),
(6, 'Fibonacci Number', 'The Fibonacci numbers form the sequence 0,1,1,2,3,5,8,... where F(n) = F(n-1) + F(n-2). Given n, calculate F(n). Use memoization to avoid recomputation.', 'EASY', 'Recursion',
 'n = 4', '3',
 '[{"input":"4","expected":"3"},{"input":"10","expected":"55"},{"input":"0","expected":"0"}]'),
(7, 'Palindrome Check', 'Given a string s, return true if it is a palindrome considering only alphanumeric characters and ignoring case, otherwise return false.', 'EASY', 'Strings',
 '"A man, a plan, a canal: Panama"', 'true',
 '[{"input":"A man, a plan, a canal: Panama","expected":"true"},{"input":"race a car","expected":"false"}]'),
(8, 'Merge Two Sorted Lists', 'Merge two sorted linked lists and return the merged sorted list. The merged list should be made by splicing together the nodes of the two lists.', 'EASY', 'LinkedList',
 'list1 = 1->2->4, list2 = 1->3->4', '1->1->2->3->4->4',
 '[{"input":"[1,2,4],[1,3,4]","expected":"[1,1,2,3,4,4]"},{"input":"[],[]","expected":"[]"}]'),
(9, 'Climbing Stairs', 'You are climbing a staircase with n steps. Each time you can climb 1 or 2 steps. In how many distinct ways can you climb to the top? This follows the Fibonacci pattern.', 'EASY', 'Dynamic Programming',
 'n = 3', '3',
 '[{"input":"3","expected":"3"},{"input":"4","expected":"5"},{"input":"5","expected":"8"}]'),
(10, 'Find All Duplicates', 'Given an integer array nums of length n where all integers are in range [1, n], return all elements that appear twice. Use O(1) extra space by negating values at index nums[i]-1.', 'MEDIUM', 'Arrays',
 'nums = [4,3,2,7,8,2,3,1]', '[2,3]',
 '[{"input":"[4,3,2,7,8,2,3,1]","expected":"[2,3]"},{"input":"[1,1,2]","expected":"[1]"}]');

